// ── Détection du type de message ──────────────────────────────
const msg = $input.item.json.message;

let userText = '';
let messageType = 'text';
let chatId = msg.chat.id;
let username = msg.from?.first_name || 'Utilisateur';

if (msg.text) {
  userText = msg.text;
  messageType = 'text';
} else if (msg.photo) {
  const caption = msg.caption || '';
  userText = `[PHOTO]${caption ? ' ' + caption : ''}`;
  messageType = 'photo';
} else if (msg.voice || msg.audio) {
  userText = '[VOCAL - Whisper non encore branché]';
  messageType = 'voice';
} else if (msg.document) {
  userText = `[DOCUMENT: ${msg.document.file_name || 'fichier'}]`;
  messageType = 'document';
} else {
  userText = '[Message non reconnu]';
  messageType = 'unknown';
}

const systemPrompt = `Tu es Agent JP, assistant IA local expert en automatisation n8n, workflows no-code, intégrations API et stratégie digitale pour PME.

Style de réponse :
- Réponds TOUJOURS en français sauf demande explicite.
- Structure claire : titre en gras, sections numérotées ou listes.
- Concis et actionnable : pas de blabla, directement utile.
- Termine TOUJOURS par une question pertinente pour approfondir.
- Si tu ne sais pas quelque chose, dis-le honnêtement.

Contexte technique :
- Tu tournes en local sur GMKtec NucBox K10 (Intel i9, 64GB RAM, Ubuntu 24).
- Stack : n8n + Ollama + qwen2.5 / llama3.1.
- Spécialités : immobilier, santé, lead generation, automatisation PME.`;

return [
  {
    json: {
      chatId,
      username,
      userText,
      messageType,
      systemPrompt,
      timestamp: new Date().toISOString()
    }
  }
];

// ── Formatage Markdown pour Telegram ──────────────────────────
// Le node Ollama (@n8n/n8n-nodes-langchain.ollama) retourne
// la réponse dans $json.message (string directe)
const raw = $json.message || $json.text || $json.content || '';
const chatId = $('⚙️ Code Prep & Detect Type1').item.json.chatId;

let formatted = raw
  // Headers # → *Titre*
  .replace(/^#{1,2}\s+(.+)$/gm, '*$1*')
  // Headers ### → _Sous-titre_
  .replace(/^#{3,}\s+(.+)$/gm, '_$1_')
  // Bold **text** → *text*
  .replace(/\*\*(.+?)\*\*/g, '*$1*')
  // Italic *text* → _text_
  .replace(/(?<!\n)\*([^*\n]+)\*/g, '_$1_')
  // Listes - / * → •
  .replace(/^[\-\*]\s+/gm, '• ')
  // Nettoyer lignes vides multiples
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// Sécurité longueur Telegram (4096 chars max)
if (formatted.length > 4000) {
  formatted = formatted.substring(0, 3990) + '...\n\n_[Réponse tronquée]_';
}

return [
  {
    json: {
      chatId,
      formattedResponse: formatted
    }
  }
];
